proof fn phi_1_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    execution_equality::<int>(ex1, ex2);
}

proof fn phi_2_suffix_zero_equals_self(ex: Execution<int>)
    ensures
        ex.suffix(0) == ex,
{
    execution_equality::<int>(ex, ex.suffix(0));
}

proof fn phi_3_always_to_current_no_axiom_needed(ex: Execution<int>, p: TempPred<int>)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex),
{
    always_to_current::<int>(ex, p);
}

proof fn phi_4_always_at_arbitrary_suffix(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    execution_equality::<int>(ex.suffix(i), ex.suffix(i));
}

proof fn phi_5_suffix_composition_equals_addition(ex: Execution<int>, i: nat, j: nat)
    ensures
        ex.suffix(i).suffix(j) == ex.suffix(i + j),
{
    execution_equality::<int>(ex.suffix(i).suffix(j), ex.suffix(i + j));
}
